const __pageData = JSON.parse('{"title":"桌面UI框架：从原生到Web技术","description":"系统梳理桌面UI框架的技术谱系，从原生控件渲染、Web技术渲染到自绘引擎的理论基础出发，深入探讨 Electron、Tauri、Flutter Desktop、React Native Desktop、Wails 与 Neutralinojs 的工程实践，并覆盖菜单栏、系统托盘、快捷键、文件拖放与通知中心等桌面专属UI模式及跨平台适配策略。","frontmatter":{"title":"桌面UI框架：从原生到Web技术","description":"系统梳理桌面UI框架的技术谱系，从原生控件渲染、Web技术渲染到自绘引擎的理论基础出发，深入探讨 Electron、Tauri、Flutter Desktop、React Native Desktop、Wails 与 Neutralinojs 的工程实践，并覆盖菜单栏、系统托盘、快捷键、文件拖放与通知中心等桌面专属UI模式及跨平台适配策略。","date":"2026-05-01T00:00:00.000Z","tags":["desktop","electron","tauri","flutter","react-native","wails","neutralinojs","ui-framework","cross-platform","gpu-acceleration"],"category":"engineering"},"headers":[],"relativePath":"desktop-development/03-desktop-ui-frameworks.md","filePath":"desktop-development/03-desktop-ui-frameworks.md","lastUpdated":1777741461000}');
